batchUpdate#

const App = () => {
  const [count, setCount] = useState(0);
  const onClick1 = () => {
    setCount(count + 1);
    setCount(count + 1);
    setCount(count + 1);
  };
  const onClick2 = () => {
    setCount((baseState) => baseState + 1);
    setCount((baseState) => baseState + 1);
    setCount(count + 1);
    setCount((baseState) => baseState + 1);
  };
  const onClick3 = () => {
    setTimeout(() => {
      // concurrent mode일 경우 배치됨, legacy mode일 경우 3번 랜딩됨.
      setCount(count + 1);
      setCount(count + 1);
      setCount(count + 1);
    }, 0);
  };
  return (
    <>
      <h1>{count}</h1>
      <div onClick={onClick1}>click1</div>
      <div onClick={onClick2}>click2</div>
      <div onClick={onClick3}>click3</div>
    </>
  );
};



high priority task#

const arr = [];
arr.length = 6000;
arr.fill(0);

const App = () => {
  const btnRef = useRef(null);
  const [count, setCount] = useState(0);
  const onClick = () => {
    setCount((count) => count + 1);
  };

  useEffect(() => {
    // 레거시 모드에서는 10, 11로 화면에 노출
    // 동시성 모드에서는 1, 11로 화면에 노출(1차 우선순위 높은거 실행, 2차 순차적으로 실행.)
    // [10_2, x+1_1]
    setTimeout(() => {
      setCount(count + 10);
    }, 2000);
    setTimeout(() => {
      btnRef.current.click();
    }, 2000);
  }, []);
  return (
    <>
      <h1>{count}</h1>
      <div
        onClick={onClick}
        ref={btnRef}
      >
        click1
      </div>
      {arr.map(() => (
        <div>{count}</div>
      ))}
    </>
  );
};



